+        double max_x = round ( max_x_/grid_scale_x_ ) *  grid_scale_x_;
+        for ( p0.x() = min_x; p0.x() <= max_x; p0.x() +=grid_scale_x_ ) {
+            p0.y() = round ( max_y_/grid_scale_y_ )  *  grid_scale_y_;
+            p1.x() = p0.x();
+            p1.y() = round ( min_y_/grid_scale_y_ )  *  grid_scale_y_;
+            pm0 = w2m ( p0 );
